332→ */
333→void LogMessageDump(scpi_t * context) {
334→
335→    char tempBuffer[LOG_MESSAGE_SIZE];
336→    bool hasMessage;
337→
338→    if (context == NULL || context->interface == NULL || context->interface->write == NULL) {
339→        return;
340→    }
341→
342→    if (logBuffer.mutex == NULL) {
343→        return;
344→    }
345→
346→    // Pop-and-print loop: mutex held only during memory copy, not I/O
347→    do {
348→        hasMessage = false;
349→
350→        // Critical section: pop one message from buffer
351→        if (xSemaphoreTake(logBuffer.mutex, portMAX_DELAY) == pdTRUE) {
352→            if (logBuffer.count > 0) {
353→                // Copy message to local stack buffer
354→                strncpy(tempBuffer, logBuffer.entries[logBuffer.tail].message, LOG_MESSAGE_SIZE - 1);
355→                tempBuffer[LOG_MESSAGE_SIZE - 1] = '\0';
356→
357→                // Advance tail and decrement count
358→                logBuffer.tail = (logBuffer.tail + 1) % LOG_MAX_ENTRY_COUNT;
359→                logBuffer.count--;
360→
361→                hasMessage = true;
362→            }
363→            xSemaphoreGive(logBuffer.mutex);
364→        }
365→
366→        // I/O section: write message (mutex released)
367→        if (hasMessage) {
368→            context->interface->write(context, tempBuffer, strlen(tempBuffer));
369→            if (context->interface->flush) {
370→                context->interface->flush(context);
371→            }
372→        }
373→    } while (hasMessage);
374→}
