506→void BQ24297_ManageIINLIM(bool vbusPresent) {
507→    TickType_t now = xTaskGetTickCount();
508→
509→    switch (pData->iinlimState) {
510→        case IINLIM_STATE_IDLE:
511→            if (vbusPresent && !pData->iinlimLastVbus) {
512→                // Rising edge — VBUS just appeared
513→                LOG_D("IINLIM: VBUS appeared, entering WAIT_DPDM");
514→                pData->iinlimTimestamp = now;
515→                pData->iinlimState = IINLIM_STATE_WAIT_DPDM;
516→            }
517→            break;
518→
519→        case IINLIM_STATE_WAIT_DPDM:
520→            if (!vbusPresent) {
521→                LOG_D("IINLIM: VBUS lost during WAIT_DPDM, returning to IDLE");
522→                pData->iinlimState = IINLIM_STATE_IDLE;
523→                break;
524→            }
525→            {
526→                TickType_t elapsed = now - pData->iinlimTimestamp;
527→
528→                // Wait at least 1s after VBUS before acting on DPDM result
529→                // to ensure BQ24297 hardware has fully settled
530→                if (elapsed < pdMS_TO_TICKS(IINLIM_DPDM_MIN_WAIT_MS)) {
531→                    break;
532→                }
533→
534→                // Check REG07 bit 7 for DPDM in progress
535→                uint8_t reg07 = 0xFF;
536→                bool dpdmDone = BQ24297_Read_I2C(0x07, &reg07) && !(reg07 & 0x80);
537→                bool timeout = elapsed >= pdMS_TO_TICKS(IINLIM_DPDM_TIMEOUT_MS);
538→
539→                if (dpdmDone) {
540→                    // DPDM finished — safe to set IINLIM, hardware won't overwrite
541→                    if (BQ24297_SetIINLIM(ILim_500)) {
542→                        LOG_D("IINLIM: DPDM done after %lu ms, set 500mA, entering WAIT_USB",
543→                              (unsigned long)(elapsed * portTICK_PERIOD_MS));
544→                        pData->iinlimTimestamp = now;
545→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
546→                    } else {
547→                        LOG_E("IINLIM: Failed to set 500mA, retrying next cycle");
548→                    }
549→                } else if (timeout) {
550→                    // DPDM stuck after 3s — set IINLIM anyway
551→                    LOG_E("IINLIM: DPDM not complete after 3s (REG07=0x%02X), forcing 500mA",
552→                          reg07);
553→                    if (BQ24297_SetIINLIM(ILim_500)) {
554→                        pData->iinlimTimestamp = now;
555→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
556→                    } else {
557→                        LOG_E("IINLIM: Failed to set 500mA on timeout, retrying next cycle");
558→                    }
559→                }
560→            }
561→            break;
562→
563→        case IINLIM_STATE_WAIT_USB:
564→            if (!vbusPresent) {
565→                BQ24297_SetIINLIM(ILim_500);
566→                LOG_D("IINLIM: VBUS lost during WAIT_USB, reset to 500mA");
